import { Component, computed, input } from '@angular/core';

interface HitoConfigView {
  hitoConfigId: number;
  hitoId: number;
  nombre: string;
  carril: string;
  grupoParalelo: { id: number; nombre: string } | null;
  orden: number;
  activo: boolean;
  subetapas: SubetapaConfigView[];
}

interface SubetapaConfigView {
  subetapaConfigId: number | null;
  subetapaId: number;
  nombre: string;
  categoria: string;
  campoStagingVin: string | null;
  orden: number;
  activo: boolean;
}

interface HitoNode {
  nombre: string;
  carril: string;
  subetapas: string[];
}

interface Bloque {
  grupoId: number;
  financiero: HitoNode[];
  operativo: HitoNode[];
}

@Component({
  selector: 'kf-process-preview',
  standalone: true,
  imports: [],
  template: `
  <div class="bg-white rounded-lg border border-slate-200 p-6 overflow-x-auto">
    <h3 class="text-sm font-semibold text-slate-700 mb-5">Vista previa del proceso</h3>

    <div class="flex flex-nowrap min-w-max">

      <!-- Carril labels (left fixed column) -->
      <div class="flex flex-col shrink-0 mr-3">
        <!-- Financiero label -->
        <div class="flex items-center h-10 mb-1">
          <div class="flex items-center gap-1.5 px-2.5 py-1 rounded-md bg-blue-50 border border-blue-200">
            <span class="w-1.5 h-1.5 rounded-full bg-blue-500"></span>
            <span class="text-xs font-semibold text-blue-700 uppercase tracking-wide whitespace-nowrap">Financiero</span>
          </div>
        </div>
        <!-- Spacer for the divider line -->
        <div class="h-px my-2"></div>
        <!-- Operativo label -->
        <div class="flex items-center h-10">
          <div class="flex items-center gap-1.5 px-2.5 py-1 rounded-md bg-amber-50 border border-amber-200">
            <span class="w-1.5 h-1.5 rounded-full bg-amber-500"></span>
            <span class="text-xs font-semibold text-amber-700 uppercase tracking-wide whitespace-nowrap">Operativo</span>
          </div>
        </div>
      </div>

      <!-- Groups flow -->
      @for (bloque of bloques(); track bloque.grupoId; let first = $first; let last = $last) {

        <!-- Dashed vertical separator between groups -->
        @if (!first) {
          <div class="flex flex-col items-center shrink-0 mx-2">
            <!-- Arrow top -->
            <div class="flex items-center mb-1">
              <div class="w-5 h-0.5 bg-slate-300"></div>
              <div class="w-0 h-0 border-t-[3px] border-b-[3px] border-l-[5px] border-transparent border-l-slate-300"></div>
            </div>
            <!-- Dashed vertical line spanning both lanes -->
            <div class="flex-1 w-px border-l border-dashed border-slate-300 min-h-16"></div>
            <!-- Arrow bottom -->
            <div class="flex items-center mt-1">
              <div class="w-5 h-0.5 bg-slate-300"></div>
              <div class="w-0 h-0 border-t-[3px] border-b-[3px] border-l-[5px] border-transparent border-l-slate-300"></div>
            </div>
          </div>
        }

        <!-- Group column (two rows: financiero + operativo) -->
        <div class="flex flex-col shrink-0 min-w-28">

          <!-- Financiero row -->
          <div class="flex gap-2 min-h-10 mb-1 items-start">
            @for (hito of bloque.financiero; track hito.nombre) {
              <div class="flex flex-col items-center">
                <div class="w-9 h-9 rounded-full flex items-center justify-center border-2
                            border-blue-400 bg-blue-50 text-blue-500 shrink-0">
                  <svg class="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
                    <circle cx="12" cy="12" r="5"/>
                  </svg>
                </div>
                <span class="mt-1 text-xs font-semibold text-slate-700 text-center leading-tight max-w-24">
                  {{ hito.nombre }}
                </span>
                @if (hito.subetapas.length > 0) {
                  <div class="mt-1.5 w-full bg-blue-50/50 rounded border border-blue-100 px-1.5 py-1 max-w-28">
                    @for (sub of hito.subetapas; track sub) {
                      <div class="flex items-center gap-1 py-px">
                        <span class="w-1 h-1 rounded-full bg-blue-300 shrink-0"></span>
                        <span class="text-[10px] text-blue-600/80 leading-tight truncate" [title]="sub">{{ sub }}</span>
                      </div>
                    }
                  </div>
                }
              </div>
            }
            @if (bloque.financiero.length === 0) {
              <div class="flex items-center justify-center h-9 w-full">
                <span class="text-slate-200 text-xs">—</span>
              </div>
            }
          </div>

          <!-- Horizontal divider (carril separator) -->
          <div class="h-px bg-slate-100 my-2"></div>

          <!-- Operativo row -->
          <div class="flex gap-2 min-h-10 items-start">
            @for (hito of bloque.operativo; track hito.nombre) {
              <div class="flex flex-col items-center">
                <div class="w-9 h-9 rounded-full flex items-center justify-center border-2
                            border-amber-400 bg-amber-50 text-amber-500 shrink-0">
                  <svg class="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
                    <circle cx="12" cy="12" r="5"/>
                  </svg>
                </div>
                <span class="mt-1 text-xs font-semibold text-slate-700 text-center leading-tight max-w-24">
                  {{ hito.nombre }}
                </span>
                @if (hito.subetapas.length > 0) {
                  <div class="mt-1.5 w-full bg-amber-50/50 rounded border border-amber-100 px-1.5 py-1 max-w-28">
                    @for (sub of hito.subetapas; track sub) {
                      <div class="flex items-center gap-1 py-px">
                        <span class="w-1 h-1 rounded-full bg-amber-300 shrink-0"></span>
                        <span class="text-[10px] text-amber-600/80 leading-tight truncate" [title]="sub">{{ sub }}</span>
                      </div>
                    }
                  </div>
                }
              </div>
            }
            @if (bloque.operativo.length === 0) {
              <div class="flex items-center justify-center h-9 w-full">
                <span class="text-slate-200 text-xs">—</span>
              </div>
            }
          </div>
        </div>
      }
    </div>

    <!-- Legend -->
    <div class="mt-6 pt-4 border-t border-slate-100 flex flex-wrap gap-5 text-xs text-slate-500">
      <span class="flex items-center gap-1.5">
        <span class="w-3 h-3 rounded-full border-2 border-blue-400 bg-blue-50"></span> Carril financiero
      </span>
      <span class="flex items-center gap-1.5">
        <span class="w-3 h-3 rounded-full border-2 border-amber-400 bg-amber-50"></span> Carril operativo
      </span>
      <span class="flex items-center gap-1.5">
        <span class="w-4 h-px border-t border-dashed border-slate-400"></span>
        Grupo paralelo (se ejecutan simultáneamente)
      </span>
      <span class="flex items-center gap-1.5">
        <svg class="w-3.5 h-3.5 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
          <path stroke-linecap="round" stroke-linejoin="round" d="M13 7l5 5-5 5M6 12h12"/>
        </svg>
        Secuencia entre grupos
      </span>
    </div>
  </div>
  `,
})
export class ProcessPreviewComponent {
  hitos = input.required<HitoConfigView[]>();

  bloques = computed(() => {
    const active = this.hitos().filter(h => h.activo).sort((a, b) => a.orden - b.orden);

    const grupoMap = new Map<number, HitoConfigView[]>();
    for (const h of active) {
      const gid = h.grupoParalelo?.id ?? 0;
      if (!grupoMap.has(gid)) grupoMap.set(gid, []);
      grupoMap.get(gid)!.push(h);
    }

    const toNode = (h: HitoConfigView): HitoNode => ({
      nombre: h.nombre,
      carril: h.carril,
      subetapas: h.subetapas
        .filter(s => s.activo)
        .sort((a, b) => a.orden - b.orden)
        .map(s => s.nombre),
    });

    return [...grupoMap.entries()]
      .map(([gid, hitos]) => ({
        grupoId: gid,
        minOrden: Math.min(...hitos.map(h => h.orden)),
        financiero: hitos.filter(h => h.carril === 'financiero').map(toNode),
        operativo: hitos.filter(h => h.carril === 'operativo').map(toNode),
      }))
      .sort((a, b) => a.minOrden - b.minOrden);
  });
}
